class Solution:
    def leastOpsExpressTarget(self, x: int, target: int) -> int:
        if target < x:
            return target - 1
        if target == x:
            return 0
        res = float('inf')
        for i in range(19, -1, -1):
            if x ** i <= target:
                res = min(res, i + (target - x ** i + x - 1) // (x - 1))
        return res
```
